defs.script:


var clock = {

  options: {
    dial               : "bauhaus",
    hourHand           : "german",
    minuteHand         : "german",
    secondHand         : "german",
    axisCover          : "circle",
    minuteHandBehavior : "stepping",
    secondHandBehavior : "swinging",
    secondHandStopTime : 1.5,
    backgroundColor    : "",
    dialColor          : "#505050",
    hourHandColor      : "#212121",
    minuteHandColor    : "#212121",
    secondHandColor    : "#d11e00",
    axisCoverColor     : "#232323",
    axisCoverRadius    : 9,
    shadowOpacity      : 0.5,
    shadowOffsetX      : 3,
    shadowOffsetY      : 3,
    shadowBlurring     : 1
  },

  timerId: undefined,

  elements: {
    dial       : ['Bauhaus', 'Austria', 'Vienna', 'Points', 'Din41091.1', 'Din41091.3', 'Din41091.4', 'RomanNumerals', 'Palmerstone', 'Aubigny', 'Wandelhalle'],
    hourHand   : ['Bauhaus', 'German', 'Siemens', 'Siemens2', 'Din41092.3', 'BigBang', 'Wandelhalle', 
                  'ZurichEnge', 'Ottensen', 'NewYork', 'Samurai', 'Westminster', 'Aubigny', 'Vienna', 'Palmerstone'],
    minuteHand : ['Bauhaus', 'German', 'Siemens', 'Siemens2', 'Din41092.3', 'BigBang', 'Wandelhalle', 
                  'ZurichEnge', 'Ottensen', 'NewYork', 'Samurai', 'Westminster', 'Aubigny', 'Vienna', 'Palmerstone'],
    secondHand : ['Bar', 'Bauhaus', 'German', 'Din41071.1', 'Din41071.2', 'BigBang', 'Wandelhalle', 'Samurai', 'Swiss'],
    axisCover  : ['Circle', 'Hexagon', 'Octagon']
  },

  initialize: function() {
    const setOptionValue = (name, value) => {
      const val = ['secondHandStopTime', 'axisCoverRadius', 'shadowOpacity', 'shadowOffsetX', 'shadowOffsetY', 'shadowBlurring']
                  .includes(name) ? this.parseNumber(value, 0) : value
      this.options[name] = val               
    }

    if (this.timerId) {
      window.clearInterval(this.timerId)
    }

    if (document.getElementById('background') &&
        document.getElementById('dial') &&
        document.getElementById('hourHand') &&
        document.getElementById('minuteHand') &&
        document.getElementById('secondHand') &&
        document.getElementById('axisCover')) {

      // initialize options via url
      const href = document.defaultView.location.href
      if (href.indexOf('?') != -1) {
        const params = href.split('?')[1].split(/&|;/)
        for (var param of params) {
          const keyValue = param.split('=')
          setOptionValue(unescape(keyValue[0]), unescape(keyValue[1]))
        }
      }

      // initialize options via parameter
      if (document.defaultView.frameElement) {
        const params = document.defaultView.frameElement.getElementsByTagName('param')
        for (var param of params) {
          setOptionValue(param.name, param.value)
        }
      }          

      for (var element of ['background', 'dial', 'hourHand', 'minuteHand', 'secondHand', 'axisCover']) {
        this.setColor(element, this.options[element + 'Color'])
      }
      for (var element of ['dial', 'hourHand', 'minuteHand', 'secondHand', 'axisCover']) {
        this.setElement(element, this.options[element])
      }
      this.setAxisCoverRadius(this.options.axisCoverRadius)
      this.setShadow(this.options.shadowOpacity,
                     this.options.shadowOffsetX,
                     this.options.shadowOffsetY,
                     this.options.shadowBlurring)

      this.draw()
      this.showElement('clock', true)

      this.timerId = window.setInterval(() => { this.draw() }, 25)
    } else {
      window.setTimeout(()  => { this.initialize() }, 10)
    }
  },

  draw: function() {
    const now     = new Date()
    const hours   = now.getHours()
    const minutes = now.getMinutes()
    var   seconds = now.getSeconds()
    var   millis  = now.getMilliseconds()

    this.rotateElement('hourHand', 30 * hours + 0.5 * minutes)
    this.rotateElement('minuteHand', 6 * minutes + (this.options.minuteHandBehavior === 'sweeping' ? 0.1 * seconds : 0))

    const fact = 60 / (60 - Math.min(30, Math.max(0, this.parseNumber(this.options.secondHandStopTime, 5))))
    const time = Math.min(60000, fact * (1000 * seconds + millis))
    seconds = Math.floor(time / 1000)
    millis  = time % 1000

    var secondAngle = 6 * seconds
    if (this.options.secondHandBehavior === 'sweeping') {
      secondAngle += 0.006 * millis
    } else if (this.options.secondHandBehavior === 'swinging') {
      secondAngle += 3 * (1 + Math.cos(Math.PI + Math.PI * (0.001 * millis)))
    }
    this.rotateElement('secondHand', secondAngle)
  },

  setColor: function(name, color) {
    const element = document.getElementById(name)
    if (element && color) {
      element.setAttribute('style', 'fill:' + color + '; stroke:' + color)
      this.options[name + 'Color'] = color
    }
  },

  setElement: function(name, value) {
    this.options[name] = 'none'
    for (var element of this.elements[name]) {
      if (element === this.capitalize(value)) {
        this.showElement(name + element, true)
        this.options[name] = value
      } else {
        this.showElement(name + element, false)
      }
    }
  },

  setAxisCoverRadius: function(value) {
    const makePoints = function(sides, radius) {
      var angle  = 2 * Math.PI / (sides * 2)
      var points = ''
      for (var i = 0; i < sides; i++) {
        points += (100 + radius * Math.sin(angle)) + ',' + (100 + radius * Math.cos(angle)) + ' '
        angle  += 2 * Math.PI / sides
      }
      return points
    }
    this.options.axisCoverRadius = this.parseNumber(value, 0)
    document.getElementById('axisCoverCircle').setAttribute('r', this.options.axisCoverRadius)
    document.getElementById('axisCoverHexagon').setAttribute('points', makePoints(6, this.options.axisCoverRadius))
    document.getElementById('axisCoverOctagon').setAttribute('points', makePoints(8, this.options.axisCoverRadius))
  },

  setShadow: function(opacity, offsetX, offsetY, blurring) {
    const setAttributes = (name, height) => {
      document.getElementById(name).setAttribute('opacity', Math.max(0, Math.min(1, opacity)))
      document.getElementById(name).setAttribute('transform', 'translate(' + offsetX * height + ',' + offsetY * height + ')')
    }
    this.options.shadowOpacity  = Math.round((opacity + Number.EPSILON) * 100) / 100
    this.options.shadowOffsetX  = offsetX
    this.options.shadowOffsetY  = offsetY
    this.options.shadowBlurring = blurring
    setAttributes('shadowHourHand', 0.5)
    setAttributes('shadowMinuteHand', 0.75)
    setAttributes('shadowSecondHand', 1)
    document.getElementById('shadowBlurring').setAttribute('stdDeviation', Math.max(0.001, blurring))
  },

  showElement: function(id, visible) {
    document.getElementById(id).setAttribute('visibility', visible ? 'visible' : 'hidden')
  },

  rotateElement: function(id, angle) {
    document.getElementById(id).setAttribute('transform', 'rotate(' + angle + ', 100, 100)')
  },

  parseNumber: function(value, defaultValue) {
    const result = parseFloat(value)
    return isNaN(result) ? defaultValue : result
  },

  capitalize: function(string) {
    return string && string[0].toUpperCase() + string.slice(1)
  }

}

clock.initialize()
